INSERT INTO prescriptions (id, patient_id, date, doctor_name, doctor_specialization, hospital_name, diagnosis, clinical_notes, follow_up_date) VALUES ('PRES-1000-1', 1000, NOW() - INTERVAL '7 days', 'Dr. Rafiq Hasan', 'Orthopedics', 'Mugda Medical College Hospital', 'Bilateral Osteoarthritis of Knee Joints', 'Pain, stiffness, and cracking sounds in both knees for the last 6 months, worse in the mornings and after sitting. Advised hot compression, avoidance of sitting on floor/squatting, and moderate knee exercises.', 'In 1 Month.');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1000-1', 'Tab. Naproxen 500mg', '1+0+1', 'After meals (only when pain is high)', '7 Days');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1000-1', 'Cap. Glucosamine + Chondroitin', '1+0+1', 'After meals', '2 Months');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1000-1', 'Tab. Omeprazole 20mg', '1+0+1', 'Before breakfast & dinner', '1 Month');
INSERT INTO lab_reports (id, patient_id, test_name, category, date, hospital_name, doctor_name, status, ai_interpretation) VALUES ('LAB-1000-1', 1000, 'Arthritis & Rheumatology Profile', 'Serology', NOW() - INTERVAL '7 days', 'Mugda Medical College Hospital', 'Dr. Rafiq Hasan', 'Completed', 'Uric acid level is slightly elevated, but Rheumatoid Factor is negative, suggesting OA rather than Gout or Rheumatoid Arthritis.');
INSERT INTO lab_test_results (lab_report_id, parameter, value, unit, reference_range, status) VALUES ('LAB-1000-1', 'Serum Uric Acid', '7.5', 'mg/dL', '3.5 - 7.2', 'High');
INSERT INTO lab_test_results (lab_report_id, parameter, value, unit, reference_range, status) VALUES ('LAB-1000-1', 'Rheumatoid Factor (RF)', '8', 'IU/mL', '< 14', 'Normal');
INSERT INTO lab_test_results (lab_report_id, parameter, value, unit, reference_range, status) VALUES ('LAB-1000-1', 'C-Reactive Protein (CRP)', '4.2', 'mg/L', '< 5.0', 'Normal');
INSERT INTO imaging_reports (id, patient_id, type, body_part, date, hospital_name, doctor_name, findings, impression) VALUES ('IMG-1000-1', 1000, 'X-Ray', 'Bilateral Knee Joints (AP & Lateral)', NOW() - INTERVAL '7 days', 'Mugda Medical College Hospital', 'Dr. Rafiq Hasan', 'Narrowing of the medial joint spaces in both knees. Subchondral sclerosis and osteophyte formation are noted along the margins of both joint surfaces. No joint effusion or fracture.', 'Radiological features of Bilateral Osteoarthritis of Knees (Grade-II).');
INSERT INTO patient_allergies (patient_id, allergen, severity, reaction) VALUES (1000, 'Peanuts', 'High', 'Anaphylaxis and facial swelling');
INSERT INTO patient_chronic_diseases (patient_id, disease_name, status, diagnosed_date) VALUES (1000, 'Osteoarthritis', 'Active', NOW() - INTERVAL '1 years 8 months');
INSERT INTO patient_chronic_diseases (patient_id, disease_name, status, diagnosed_date) VALUES (1000, 'Migraine', 'Active', NOW() - INTERVAL '2 years 7 months');
