INSERT INTO prescriptions (id, patient_id, date, doctor_name, doctor_specialization, hospital_name, diagnosis, clinical_notes, follow_up_date) VALUES ('PRES-1001-2', 1001, NOW() - INTERVAL '24 days', 'Dr. Fatema Ahmed', 'Ophthalmology', 'Evercare Hospital', 'Acute Bronchitis & suspected Asthma', 'Cough with sputum, shortness of breath, and chest tightness for 5 days. Wheezing heard on auscultation. Advised avoiding cold drinks, dust, and using inhaler correctly.', 'In 10 days for review of symptoms.');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1001-2', 'Tab. Azithromycin 500mg', '1+0+0', '1 hour before food', '5 Days');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1001-2', 'Tab. Montelukast 10mg', '0+0+1', 'At night', '14 Days');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1001-2', 'Inhaler Salbutamol 100mcg', '2 Puffs', 'As needed (when short of breath)', 'As needed');
INSERT INTO lab_reports (id, patient_id, test_name, category, date, hospital_name, doctor_name, status, ai_interpretation) VALUES ('LAB-1001-2', 1001, 'Complete Blood Count (CBC)', 'Hematology', NOW() - INTERVAL '24 days', 'Evercare Hospital', 'Dr. Fatema Ahmed', 'Completed', 'Mild leukocytosis observed, consistent with active respiratory tract infection. Eosinophil counts are slightly elevated, which could point to an allergic component (Asthma).');
INSERT INTO lab_test_results (lab_report_id, parameter, value, unit, reference_range, status) VALUES ('LAB-1001-2', 'Total WBC Count', '11.2', 'x10^9/L', '4.0 - 11.0', 'High');
INSERT INTO lab_test_results (lab_report_id, parameter, value, unit, reference_range, status) VALUES ('LAB-1001-2', 'Hemoglobin (Hb)', '14.5', 'g/dL', '13.5 - 17.5', 'Normal');
INSERT INTO lab_test_results (lab_report_id, parameter, value, unit, reference_range, status) VALUES ('LAB-1001-2', 'Eosinophils', '7', '%', '1 - 6', 'High');
INSERT INTO imaging_reports (id, patient_id, type, body_part, date, hospital_name, doctor_name, findings, impression) VALUES ('IMG-1001-2', 1001, 'X-Ray', 'Chest (P/A View)', NOW() - INTERVAL '24 days', 'Evercare Hospital', 'Dr. Fatema Ahmed', 'Lungs are hyperinflated. Increased bronchovascular markings seen bilaterally. Both costophrenic angles are clear. Heart size and shape are normal. Bony thorax and dome of diaphragms are intact.', 'Findings are suggestive of Acute Bronchitic changes. No consolidation or pleural effusion.');
