INSERT INTO prescriptions (id, patient_id, date, doctor_name, doctor_specialization, hospital_name, diagnosis, clinical_notes, follow_up_date) VALUES ('PRES-1079-1', 1079, NOW() - INTERVAL '17 days', 'Dr. Faruq Akter', 'Neuromedicine', 'Jashore General Hospital', 'Type 2 Diabetes Mellitus & Essential Hypertension', 'Patient presents with generalized weakness and occasional dizziness. Blood pressure and fasting blood glucose are elevated. Recommended strict dietary control, low salt, regular walking, and compliance with medications.', 'In 3 months with fasting blood sugar and lipid profile reports.');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1079-1', 'Tab. Metformin HCl 500mg', '1+0+1', 'After meals', '3 Months');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1079-1', 'Tab. Amlodipine 5mg', '0+0+1', 'At night before sleeping', '1 Month');
INSERT INTO prescription_medicines (prescription_id, name, dosage, instruction, duration) VALUES ('PRES-1079-1', 'Tab. Atorvastatin 10mg', '0+0+1', 'At night after dinner', '2 Months');
