INSERT INTO prescriptions (id, patient_id, date, doctor_name, doctor_specialization, hospital_name, diagnosis, clinical_notes, follow_up_date) VALUES ('PRES-1087-2', 1087, NOW() - INTERVAL '27 days', 'Dr. Lipi Chowdhury', 'ENT', 'National Institute of Cardiovascular Diseases', 'Acute Bronchitis & suspected Asthma', 'Cough with sputum, shortness of breath, and chest tightness for 5 days. Wheezing heard on auscultation. Advised avoiding cold drinks, dust, and using inhaler correctly.', 'In 10 days for review of symptoms.');
