INSERT INTO prescriptions (id, patient_id, date, doctor_name, doctor_specialization, hospital_name, diagnosis, clinical_notes, follow_up_date) VALUES ('PRES-1172-1', 1172, NOW() - INTERVAL '18 days', 'Dr. Khadija Begum', 'Psychiatry', 'Popular Diagnostic & Hospital', 'Acute Bronchitis & suspected Asthma', 'Cough with sputum, shortness of breath, and chest tightness for 5 days. Wheezing heard on auscultation. Advised avoiding cold drinks, dust, and using inhaler correctly.', 'In 10 days for review of symptoms.');
