INSERT INTO imaging_reports (id, patient_id, type, body_part, date, hospital_name, doctor_name, findings, impression) VALUES ('IMG-1172-1', 1172, 'X-Ray', 'Chest (P/A View)', NOW() - INTERVAL '18 days', 'Popular Diagnostic & Hospital', 'Dr. Khadija Begum', 'Lungs are hyperinflated. Increased bronchovascular markings seen bilaterally. Both costophrenic angles are clear. Heart size and shape are normal. Bony thorax and dome of diaphragms are intact.', 'Findings are suggestive of Acute Bronchitic changes. No consolidation or pleural effusion.');
INSERT INTO prescriptions (id, patient_id, date, doctor_name, doctor_specialization, hospital_name, diagnosis, clinical_notes, follow_up_date) VALUES ('PRES-1172-2', 1172, NOW() - INTERVAL '23 days', 'Dr. Mahbub Islam', 'Gastroenterology', 'Dhaka Medical College Hospital', 'Bilateral Osteoarthritis of Knee Joints', 'Pain, stiffness, and cracking sounds in both knees for the last 6 months, worse in the mornings and after sitting. Advised hot compression, avoidance of sitting on floor/squatting, and moderate knee exercises.', 'In 1 Month.');
